+    #[test]
+    fn test_pragma_connection_stats_excludes_failed_statement_attempts() {
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("pool-failed-statement-counts.db");
+        let db_path = db_path.to_string_lossy().into_owned();
+
+        let conn = Connection::open(&db_path).unwrap();
+        conn.execute("CREATE TABLE t(id INTEGER PRIMARY KEY);")
+            .unwrap();
+        conn.execute("INSERT INTO t(id) VALUES (1);").unwrap();
+
+        let before = txn_metrics_map(&conn.query("PRAGMA fsqlite.connection_stats;").unwrap());
+        let before_total = before
+            .get("queries_executed_total")
+            .copied()
+            .unwrap_or_default();
+
+        assert!(
+            conn.execute("INSERT INTO t(id) VALUES (1);").is_err(),
+            "duplicate-key INSERT should fail at execution time",
+        );
+
+        let after = txn_metrics_map(&conn.query("PRAGMA fsqlite.connection_stats;").unwrap());
+        let after_total = after
+            .get("queries_executed_total")
+            .copied()
+            .unwrap_or_default();
+
+        assert_eq!(
+            after_total.saturating_sub(before_total),
+            1,
+            "only the stats PRAGMA itself should increase successful execution counts",
+        );
+    }
